pub fn is_system_transaction(tx_type: u8) -> bool {
    matches!(tx_type, TX_TYPE_SCHEDULED | TX_TYPE_ASYNC_COMMITMENT | TX_TYPE_ASYNC_SETTLEMENT)
}

